import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  const handleCardAction = (type) => {
    if (type === 'payments') {
      alert("Redirecting to our Secure Payment Policy...");
    } else if (type === 'students') {
      // हे तुम्हाला सर्व फ्रीलान्सर्सच्या लिस्टकडे नेईल
      navigate('/services'); 
    } else if (type === 'delivery') {
      navigate('/contact');
    }
  };

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif", overflowX: 'hidden' }}>
      
      {/* 1. Hero Section */}
      <header className="hero-section text-white d-flex align-items-center" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '80vh',
          padding: '80px 0'
        }}>
        <div className="container text-center">
          <h1 className="display-2 fw-bold mb-3" style={{ letterSpacing: '-2px', textShadow: '2px 4px 10px rgba(0,0,0,0.2)' }}>
            Freelance <span style={{ color: '#ffc107' }}>Hub</span>
          </h1>
          <p className="lead fs-4 mb-5 opacity-75 mx-auto" style={{ maxWidth: '800px' }}>
            The ultimate marketplace for students to showcase skills and clients to find top-tier solutions.
          </p>
          <div className="d-flex justify-content-center gap-3 flex-wrap">
            <Link to="/services" className="btn btn-warning btn-lg px-5 py-3 fw-bold rounded-pill shadow-lg border-0">
              Hire Freelancers
            </Link>
            <Link to="/register" className="btn btn-outline-light btn-lg px-5 py-3 rounded-pill border-2">
              Join as Freelancer
            </Link> 
          </div>
        </div>
      </header>

      {/* 2. Interactive Features Section */}
      <section className="py-5 bg-white">
        <div className="container py-5">
          <div className="text-center mb-5">
            <h2 className="fw-bold display-5 text-dark">Why Choose Us?</h2>
            <div className="mx-auto mt-2" style={{ width: '70px', height: '5px', background: '#ffc107', borderRadius: '10px' }}></div>
          </div>
          
          <div className="row g-4 text-center">
            <div className="col-md-4" onClick={() => handleCardAction('payments')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">🛡️</div>
                <h4 className="fw-bold text-dark">Secure Payments</h4>
                <p className="text-muted">Safe escrow-based transactions for every single project.</p>
                <span className="text-primary fw-bold small">Learn More →</span>
              </div>
            </div>

            <div className="col-md-4" onClick={() => handleCardAction('students')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">🎓</div>
                <h4 className="fw-bold text-dark">Verified Talents</h4>
                <p className="text-muted">Work with top-rated talent from verified educational backgrounds.</p>
                <span className="text-primary fw-bold small">Browse Talent →</span>
              </div>
            </div>

            <div className="col-md-4" onClick={() => handleCardAction('delivery')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">⚡</div>
                <h4 className="fw-bold text-dark">Fast Delivery</h4>
                <p className="text-muted">Optimized workflows to ensure your projects are delivered on time.</p>
                <span className="text-primary fw-bold small">Our Guarantee →</span>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 3. Sample Freelancer Profile Section */}
      <section className="py-5" style={{ backgroundColor: '#fdfdfd' }}>
        <div className="container">
            <div className="d-flex justify-content-between align-items-end mb-4">
                <div>
                    <h2 className="fw-bold">Top Freelancers</h2>
                    <p className="text-muted">Hire the best student talent from Nashik</p>
                </div>
                <Link to="/services" className="btn btn-link text-decoration-none fw-bold">View All</Link>
            </div>
            <div className="row g-4">
                <div className="col-md-3">
                    <div className="card border-0 shadow-sm rounded-4 p-3 text-center">
                        <img src="https://freepik.com" 
                             className="rounded-circle mx-auto mb-3" style={{width: '80px'}} alt="profile" />
                        <h5 className="fw-bold mb-1">Rahul Patil</h5>
                        <p className="text-muted small mb-3">React Developer</p>
                        <div className="d-flex justify-content-center gap-1 mb-3">
                            <span className="badge bg-light text-dark border">React</span>
                            <span className="badge bg-light text-dark border">UI/UX</span>
                        </div>
                        {/* हा Route आपण App.js मध्ये सेट केला आहे */}
                        <button onClick={() => navigate('/profile/1')} className="btn btn-outline-primary btn-sm rounded-pill w-100">View Profile</button>
                    </div>
                </div>
            </div>
        </div>
      </section>

      {/* 4. Nashik Location Section - Fixed Map URL */}
      <section id="contact" className="py-5" style={{ backgroundColor: '#f8f9fa' }}>
        <div className="container text-center">
          <h2 className="fw-bold mb-5 display-6">📍 Our Hub in <span className="text-primary">Nashik</span></h2>
          <div className="shadow-lg rounded-5 overflow-hidden mx-auto border-white border-5" style={{ maxWidth: '1100px', height: '400px' }}>
            <iframe
              title="Nashik Map"
              src="https://google.com"
              width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy"></iframe>
          </div>
        </div>
      </section>

      <style>{`
        .interactive-card { transition: all 0.4s ease; background: #ffffff; }
        .interactive-card:hover { transform: translateY(-10px); box-shadow: 0 20px 40px rgba(0,0,0,0.1) !important; }
        .btn:hover { transform: translateY(-2px); box-shadow: 0 5px 15px rgba(0,0,0,0.1); }
      `}</style>

    </div>
  );
}

export default Home;
